function encode(strs: string[]): string {
  return strs.map(s => s.length + "#" + s).join("");
}
function decode(s: string): string[] {
  const out: string[] = [];
  let i = 0;
  while (i < s.length) {
    let j = i;
    while (s[j] !== "#") j++;
    const len = parseInt(s.slice(i, j), 10);
    out.push(s.slice(j + 1, j + 1 + len));
    i = j + 1 + len;
  }
  return out;
}
